        case 4:

            // 품명 팝업
            udc_con_commCd.setSelectId("retrieveCommInfo"); // XML상의 SELECT ID
            udc_con_commCd.cfCommonPopUp(scwin.udc_con_commCd_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
