                //,"3,4,,,ZZZZ" // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                //20161017 석고보드(936)을 검색할수없어 검색레벨 변경
                , "2,4,,,ZZZZ" // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "품명조회,품명코드,품명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 5:

            // 화주 팝업
            udc_stockClntCd.setSelectId("retrieveClntList"); // XML상의 SELECT ID
            udc_stockClntCd.cfCommonPopUp(scwin.udc_stockClntCd_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "화주,화주코드,화주명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 본선관리번호검색 팝업창 띄우기
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function () {
    var args = new Array();
    args[0] = ed_cvsslMgntNo.getValue(); //본선관리번호
    args[1] = ""; //수출입구분코드

    let win_url = "/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml";

    let opts = {
        id: "op_204_01_07p",
        popupName: "본선관리번호검색팝업",
        modal: true,
        type: "browserPopup",
        width: 1200,
        height: 650,
        title: "본선관리번호검색팝업"
    };

    let rtnValues = await $c.win.openPopup(win_url, opts, args);

    if (rtnValues != null) {
        ed_cvsslMgntNo.setValue(rtnValues[0]); //본선관리번호
        //rtnValues[0]; 본선관리번호
        //rtnValues[1]; 선박코드
        //rtnValues[2]; 선박명
        //rtnValues[3]; 마감일자
        //rtnValues[4]; 마감시간
        //rtnValues[5]; 도착(입항)일자
        //rtnValues[6]; 도착(입항)시간
        //rtnValues[7]; 출발(출항)일자
        //rtnValues[8]; 출발(출항)시간
        //rtnValues[9]; 선사항차
        //rtnValues[10]; 항로
        //rtnValues[11]; 항구코드
        //rtnValues[12]; 부두코드
        //rtnValues[13]; 부두코드명
    }
}

